// Calculate onboarding health scores
// In production, pull from your database
const customers = [
  { id: 'C001', name: 'Alice Chen', email: 'alice@example.com', plan: 'pro', signupDate: '2026-03-15', completedSteps: 5, totalSteps: 5, lastActive: '2026-03-22', supportTickets: 0, loginCount: 12 },
  { id: 'C002', name: 'Bob Smith', email: 'bob@example.com', plan: 'starter', signupDate: '2026-03-18', completedSteps: 2, totalSteps: 5, lastActive: '2026-03-19', supportTickets: 3, loginCount: 2 },
  { id: 'C003', name: 'Carol Davis', email: 'carol@example.com', plan: 'enterprise', signupDate: '2026-03-20', completedSteps: 3, totalSteps: 5, lastActive: '2026-03-22', supportTickets: 1, loginCount: 8 }
];

const scored = customers.map(c => {
  let score = 0;
  // Step completion (40%)
  score += (c.completedSteps / c.totalSteps) * 40;
  // Recency (30%) - days since last active
  const daysSinceActive = Math.floor((Date.now() - new Date(c.lastActive).getTime()) / 86400000);
  score += Math.max(0, 30 - (daysSinceActive * 10));
  // Engagement (20%) - login frequency
  score += Math.min(20, c.loginCount * 2);
  // Support friction (10%) - fewer tickets = better
  score += Math.max(0, 10 - (c.supportTickets * 3));

  const health = score >= 80 ? '🟢 Healthy' : score >= 50 ? '🟡 At Risk' : '🔴 Critical';
  const action = score < 50 ? 'Send re-engagement email + schedule call' : score < 80 ? 'Send helpful resource' : 'Continue drip sequence';

  return { ...c, score: Math.round(score), health, action };
});

// Sort by score ascending (worst first)
scored.sort((a, b) => a.score - b.score);

const atRisk = scored.filter(c => c.score < 80);

return [{
  json: {
    customers: scored,
    summary: {
      total: scored.length,
      healthy: scored.filter(c => c.score >= 80).length,
      atRisk: atRisk.length,
      critical: scored.filter(c => c.score < 50).length,
      avgScore: Math.round(scored.reduce((s, c) => s + c.score, 0) / scored.length)
    },
    atRiskCustomers: atRisk,
    generatedAt: new Date().toISOString()
  }
}];

